```plantuml
@startuml
title UMLObject Class Diagram

class Monitor {
  + localRelays {relay.ID : Instance}
  + localAnalogOut {analogOut.ID : Instance}
}

class MODBUSInterface {
  + ID
}

class digitalDevice {
  + modbus_channel
}

class RS485ConfigNote {
  + modbus_interface
  + protocol
  + baudRate
  + charLen
  + parity
  + stopBits
}

class digitalSensor {
  + sensors {sensor_number:address}
}

class digitalModule {
  + address
}

class relayModule {
  + relays {relay_number:local_instance}
}

class analogInputModule {
  + sensors {sensor_number:local_instance}
}

class analogOuptModule {
  + output {sensor_number:local_instance}
}

digitalDevice <|-- digitalSensor
digitalDevice <|-- digitalModule

digitalModule <|-- relayModule
digitalModule <|-- analogInputModule
digitalModule <|-- analogOuptModule

@enduml
```
